sql:
SELECT 
    (SELECT COUNT(*) FROM games WHERE team_id = 1) AS games_count,
    (SELECT SUM(points) FROM team_stats WHERE team_id = 1) AS total_points;

SELECT DISTINCT p.player_name
FROM players p
WHERE p.position = 'Point Guard' OR (p.draft_year BETWEEN 2000 AND 2099);

external_knowledge:
- "Seasoned players" refers to players who have played more than 5 games; 
- "Been part of a substantial number of battles" refers to players who have played more than 5 games; 
- "Under the guidance of a coach" refers to teams that have a user with the role of 'coach'.
